// Worked focus: httpsts-idempotency-key-fingerprint — Scope idempotency keys to principal and operation, compare canonical request fingerprints, store outcome atomically, expire deliberately, and reject mismatches.
// Evidence: httpsts-worked-http-server-ts-resource-apis-consistency-4
// Competency: httpsts-worked-http-server-ts-resource-apis-consistency-4.
// Case 1655: privacy-sensitive records API using conditional requests.
// Operating constraint: retain a screen-reader-readable decision trace.
// Changed case: abort during a dependency phase and preserve cleanup plus response ownership.
function worked_http_server_ts_resource_apis_consistency_4(fingerprintMatches: boolean, expectedVersion: number, actualVersion: number, outboxStored: boolean): { status: number; decision: string; publish: boolean } {
  if (!fingerprintMatches) return { status: 409, decision: "idempotency-mismatch", publish: false };
  if (expectedVersion !== actualVersion) {
    return { status: 412, decision: "version-conflict", publish: false };
  }
  return { status: outboxStored ? 200 : 503, decision: "updated", publish: outboxStored };
}

